// frontend/src/hooks/useSensor.js
import { useBluetoothSensor } from './useBluetoothSensor';

export const useSensor = () => {
    const bluetoothSensor = useBluetoothSensor();
    
    return {
        status: {
            connected: bluetoothSensor.status.connected,
            port: bluetoothSensor.status.device?.name || 'Bluetooth'
        },
        loading: bluetoothSensor.loading,
        error: bluetoothSensor.error,
        connect: bluetoothSensor.connect,
        disconnect: bluetoothSensor.disconnect,
        scanFingerprint: bluetoothSensor.scanFingerprint,
        enrollFingerprint: bluetoothSensor.enrollFingerprint,
        isSupported: bluetoothSensor.isBluetoothSupported
    };
};
